/*
  # Seed Support FAQs - Part 3 (Pagesa, Teknike, Siguria, Platforma)

  Adds ~100 FAQ entries covering:
  - Payment & billing
  - Technical issues
  - Security
  - Platform general
*/

INSERT INTO support_faqs (category, question, answer, keywords, priority) VALUES

-- PAGESA (Payment & Billing) - 25 entries
('Pagesa', 'Si te bej pagesen e abonimit?', 'Shkoni te Cilesimet > Abonimi. Zgjidhni planin dhe metodens e pageses (karte debiti/krediti ose PayPal). Ndiqni hapat per te perfunduar pagesen.', ARRAY['pages', 'abonim', 'paguaj', 'karte', 'paypal'], 9),
('Pagesa', 'Cilat metoda pagese pranohen?', 'Pranojme karta debiti/krediti (Visa, Mastercard, Amex) dhe PayPal. Metoda te reja pagese do te shtohen se shpejti.', ARRAY['metode', 'pages', 'karte', 'visa', 'mastercard', 'paypal'], 8),
('Pagesa', 'Si te ndryshoj karten e pageses?', 'Shkoni te Cilesimet > Abonimi > Metoda e Pageses. Mund te shtoni nje karte te re ose te ndryshoni karten aktuale.', ARRAY['karte', 'ndrysho', 'pages', 'metode', 'kreditore'], 7),
('Pagesa', 'Kur behet pagesa mujore?', 'Pagesa behet automatikisht ne te njejten dite te cdo muaji kur filloi abonimi. Do te merrni fature ne email perpara cdo pagese.', ARRAY['kur', 'pages', 'mujore', 'date', 'automatik'], 7),
('Pagesa', 'A mund te anuloj abonimin?', 'Po, mund te anuloni abonimin ne cdo kohe nga Cilesimet > Abonimi. Pas anulimit, do te keni akses deri ne fund te periudhes aktuale te paguar.', ARRAY['anulo', 'abonim', 'ndalo', 'mbyll', 'largo'], 8),
('Pagesa', 'Si te marr fature per pagesen?', 'Faturat gjenden ne Cilesimet > Abonimi > Historia e Pagesave. Mund ti shkarkoni ne format PDF per kontabilitetin tuaj.', ARRAY['fature', 'pages', 'shkarko', 'pdf', 'kontabilitet'], 7),
('Pagesa', 'Pse deshtoi pagesa ime?', 'Pagesa mund te deshtoje per disa arsye: fonde te pamjaftueshme, karte e skaduar, ose kufizim nga banka. Kontrolloni te dhenat e kartes ose kontaktoni banken.', ARRAY['deshtoi', 'pages', 'gabim', 'problem', 'refuzuar'], 9),
('Pagesa', 'A ka periudhe prove falas?', 'Po, cdo kompani e re merr 14 dite prove falas. Gjate kesaj periudhe keni akses te plote pa ndonje pagese.', ARRAY['prove', 'falas', 'trial', 'dite', 'gratis'], 8),
('Pagesa', 'Sa kushton plani Standard?', 'Cmimi i planit Standard shfaqet ne faqen e planeve. Mund ta shihni edhe gjate regjistrimit ose ne Cilesimet > Abonimi.', ARRAY['kushton', 'cmim', 'standard', 'plan', 'pages'], 7),
('Pagesa', 'Sa kushton plani Premium?', 'Cmimi i planit Premium shfaqet ne faqen e planeve. Plani Premium ofron karakteristika te pakufizuara per kompani te medha.', ARRAY['kushton', 'cmim', 'premium', 'plan', 'pages'], 7),
('Pagesa', 'A ka zbritje per pagese vjetore?', 'Aktualisht ofrojme vetem pagesa mujore. Opsioni i pageses vjetore me zbritje do te shtohet se shpejti.', ARRAY['zbritje', 'vjetore', 'oferte', 'kursim', 'discount'], 5),
('Pagesa', 'Si te kthehem ne planin falas?', 'Nuk ka plan falas permanent. Mund te anuloni abonimin dhe pas skadimit, llogaria kalon ne gjendje te kufizuar pa pagese.', ARRAY['falas', 'plan', 'kthe', 'pa', 'pages'], 5),
('Pagesa', 'A jam i sigurt kur paguaj online?', 'Po, te gjitha pagesat procesohen permes Stripe qe eshte platforma me e sigurt e pagesave online. Te dhenat tuaja jane te enkriptuara.', ARRAY['sigurt', 'pages', 'online', 'enkriptim', 'mbrojtje'], 8),
('Pagesa', 'Si te marr rimbursim?', 'Per kerkese rimbursimi, kontaktoni suportin teknik. Rimbursimet procesoheni brenda 5-10 diteve pune pas miratimit.', ARRAY['rimbursim', 'kthe', 'parate', 'refund', 'rikthim'], 7),
('Pagesa', 'Cfare ndodh nese nuk paguaj?', 'Nese pagesa deshtoni, do te provoheni perseri pas 3 diteve. Pas 3 perpjekjeve te deshtuar, llogaria kalon ne gjendje te kufizuar.', ARRAY['nuk', 'paguaj', 'deshtim', 'pasoja', 'bllok'], 7),
('Pagesa', 'A mund te paguaj me transfer bankar?', 'Aktualisht nuk pranojme transfere bankare. Metodat e pranuara jane karta debiti/krediti dhe PayPal.', ARRAY['transfer', 'bankar', 'banke', 'pages', 'metode'], 5),
('Pagesa', 'Si te shoh historikun e pagesave?', 'Shkoni te Cilesimet > Abonimi > Historia e Pagesave. Aty shfaqen te gjitha pagesat me datat, shumat, dhe statuset.', ARRAY['historik', 'pages', 'lista', 'arkiv', 'transaksion'], 6),
('Pagesa', 'A mund te paguaj per disa muaj njekohesisht?', 'Aktualisht pagesa behet muaj per muaj. Opsioni i pageses per disa muaj njekohesisht do te shtohet se shpejti.', ARRAY['disa', 'muaj', 'paraprak', 'njekohesisht', 'pages'], 4),
('Pagesa', 'Cfare monedhe perdoret?', 'Pagesat behen ne Euro. Nese karta juaj eshte ne monedhe tjeter, banka juaj do te beje konvertimin automatikisht.', ARRAY['monedhe', 'euro', 'valute', 'konvertim', 'lek'], 5),
('Pagesa', 'A jam i detyruar te paguaj pas proves falas?', 'Jo, nuk ka detyrim. Nese nuk zgjidhni nje plan me pagese, llogaria thjesht kalon ne gjendje te kufizuar pa ndonje tarife.', ARRAY['detyruar', 'prove', 'falas', 'automatik', 'pages'], 7),
('Pagesa', 'Si te perditesoj planin tim?', 'Shkoni te Cilesimet > Abonimi dhe klikoni "Ndrysho Planin". Zgjidhni planin e ri dhe konfirmoni ndryshimin.', ARRAY['perditsoj', 'plan', 'upgrade', 'ndrysho', 'ngrije'], 7),
('Pagesa', 'A ka kosto shtese per perdorues?', 'Jo, cmimi i planit mbulon te gjithe perdoruesit brenda limiteve te planit. Nuk ka tarifa shtese per perdorues.', ARRAY['kosto', 'shtese', 'perdorues', 'tarife', 'ekstra'], 6),
('Pagesa', 'Cfare perfshine plani Standard?', 'Plani Standard perfshin: deri ne 5 depo, 10 shofere, chat te pakufizuar, dokumente, raporte baze, dhe suport teknik.', ARRAY['standard', 'perfshin', 'karakteristika', 'vecore', 'plan'], 7),
('Pagesa', 'Cfare perfshine plani Premium?', 'Plani Premium perfshin: depo dhe shofere te pakufizuar, raporte te avancuara, prioritet ne suport, dhe te gjitha karakteristikat.', ARRAY['premium', 'perfshin', 'karakteristika', 'vecore', 'plan'], 7),
('Pagesa', 'A mund te ndal abonimin perkohesisht?', 'Aktualisht nuk ka mundesi pezullimi. Mund te anuloni dhe te ri-abonoheni me vone. Te dhenat ruhen per 90 dite pas anulimit.', ARRAY['ndal', 'pezullo', 'perkohesisht', 'pauz', 'nderprit'], 5),

-- TEKNIKE (Technical Issues) - 25 entries
('Teknike', 'Faqja nuk ngarkohet, cfare te bej?', 'Provoni keto hapa: 1) Rifreskoni faqen (F5), 2) Pastroni cache-in e shfletuesit, 3) Provoni nje shfletues tjeter, 4) Kontrolloni lidhjen e internetit.', ARRAY['nuk', 'ngarko', 'faqe', 'problem', 'zbrazet', 'bosh'], 10),
('Teknike', 'Shfletuesi im nuk suportohet?', 'Platforma suporton Chrome 80+, Firefox 75+, Safari 13+, dhe Edge 80+. Perditesoni shfletuesin tuaj ne versionin me te fundit.', ARRAY['shfletues', 'suport', 'version', 'perputhshmeri', 'browser'], 7),
('Teknike', 'Si te pastroj cache-in e shfletuesit?', 'Chrome: Ctrl+Shift+Delete > Zgjidhni "Cached images and files" > Delete. Firefox: Ctrl+Shift+Delete > Zgjidhni "Cache" > Clear.', ARRAY['cache', 'pastro', 'shfletues', 'memorie', 'fshij'], 7),
('Teknike', 'Pse eshte e ngadaleshem platforma?', 'Shpejtesia varet nga lidhja e internetit dhe pajisja juaj. Provoni: 1) Mbyllni skedat e tjera, 2) Rifreskoni faqen, 3) Provoni nje rrjet me te shpejt.', ARRAY['ngadale', 'shpejt', 'vonese', 'performanc', 'problem'], 8),
('Teknike', 'Nuk me shfaqen imazhet, cfare ndodh?', 'Kontrolloni lidhjen e internetit. Nese lidhja eshte ne rregull, provoni te pastroni cache-in ose te rifreskoni faqen. Disa rrjete bllokojne imazhet.', ARRAY['imazh', 'foto', 'nuk', 'shfaq', 'mungon', 'bllok'], 7),
('Teknike', 'Si te bej screenshot per te raportuar problem?', 'Windows: Ctrl+Shift+S ose Print Screen. Mac: Cmd+Shift+4. Pastaj ngarkoni screenshot-in ne chat-in e suportit.', ARRAY['screenshot', 'foto', 'ekran', 'raportoj', 'problem', 'kapje'], 5),
('Teknike', 'Pse marr gabimin "403 Forbidden"?', 'Ky gabim do te thote qe nuk keni leje per te aksesuar kete faqe. Kontrolloni qe jeni hyre me rolin e duhur ose kontaktoni administratorin.', ARRAY['403', 'forbidden', 'gabim', 'leje', 'akses', 'ndaluar'], 8),
('Teknike', 'Pse marr gabimin "404 Not Found"?', 'Faqja nuk u gjet. Kontrolloni URL-ne ose shkoni ne faqen kryesore dhe navigoni drejt faqes qe kerkoni.', ARRAY['404', 'not found', 'gabim', 'faqe', 'mungon'], 6),
('Teknike', 'Pse marr gabimin "500 Server Error"?', 'Ky eshte nje gabim i serverit. Zakonisht zgjidhet vete brenda disa minutave. Nese vazhdon, kontaktoni suportin teknik.', ARRAY['500', 'server', 'gabim', 'error', 'problem', 'rrezi'], 9),
('Teknike', 'Platforma nuk funksionon ne telefonin tim', 'Sigurohuni qe keni shfletuesin e perditesuar. Provoni: 1) Pastroni cache-in, 2) Mbyllni dhe rihapni shfletuesin, 3) Provoni nje shfletues tjeter.', ARRAY['telefon', 'mobile', 'nuk', 'funksionon', 'problem'], 8),
('Teknike', 'Nuk mund te ngarkoj skedare, pse?', 'Kontrolloni: 1) Madhesia e skedarit (max 50MB), 2) Formati (sigurohuni qe eshte format i pranuar), 3) Lidhja e internetit eshte stabile.', ARRAY['ngarkoj', 'skedar', 'nuk', 'mundem', 'gabim', 'upload'], 8),
('Teknike', 'Si te kontrolloj versionin e platformes?', 'Versioni shfaqet ne fund te faqes (footer) ose ne Cilesimet > Rreth. Sigurohuni qe perdorni gjithmone versionin e fundit.', ARRAY['version', 'perditesim', 'update', 'numri', 'aktual'], 4),
('Teknike', 'A ka kohe mirembajtjeje te planifikuar?', 'Mirembajt e planifikuara njoftohen paraprakisht permes emailit dhe njoftimeve ne platform. Zakonisht behen naten per te minimizuar nderprerjent.', ARRAY['mirembajtje', 'planifikuar', 'offline', 'nderprerje', 'pushim'], 5),
('Teknike', 'Pse humba te dhenat qe sapo futa?', 'Nese lidhja e internetit u nderpre gjate ruajtjes, te dhenat mund te mos jene ruajtur. Provoni perseri dhe sigurohuni qe shihni konfirmimin e ruajtjes.', ARRAY['humba', 'te dhena', 'ruajtje', 'futa', 'nuk', 'ruajt'], 9),
('Teknike', 'Si te rifreskoj faqen pa humbur te dhenat?', 'Nese keni forma te paplotesuar, ruajini perpara rifreskimit. Per rifreskim te thjesht, shtypni F5 ose terhiqni poshte ne telefon.', ARRAY['rifresko', 'faqe', 'humb', 'te dhena', 'reload'], 6),
('Teknike', 'Pse sesioni im skadon shpesh?', 'Sesioni skadon pas nje periudhe joaktiviteti per arsye sigurie. Nese kjo ndodh shpesh, sigurohuni qe cookies jane te aktivizuara ne shfletues.', ARRAY['sesion', 'skadon', 'shpesh', 'shkyc', 'kohe'], 6),
('Teknike', 'A mund te perdor VPN me platformen?', 'Po, platforma funksionon me VPN. Nese hasni probleme, provoni te caktivizoni VPN-ne perkohesisht per te pare nese eshte shkaku.', ARRAY['vpn', 'rrjet', 'proxy', 'lidhje', 'bllok'], 4),
('Teknike', 'Si te aksesoj platformen nga nje pajisje e re?', 'Thjesht hapni shfletuesin ne pajisjen e re dhe hyni me emailin dhe fjalekalimin tuaj. Nuk ka kufizim ne numrin e pajisjeve.', ARRAY['pajisje', 'reja', 'kompjuter', 'telefon', 'akses'], 6),
('Teknike', 'Njoftimet nuk funksionojne, cfare te bej?', 'Kontrolloni: 1) Njoftimet jane te aktivizuara ne shfletues, 2) Nuk jeni ne modalitetin "Do Not Disturb", 3) Provoni te rifreskoni faqen.', ARRAY['njoftim', 'nuk', 'funksionon', 'problem', 'zile'], 7),
('Teknike', 'Si te kontrolloj lidhjen time te internetit?', 'Hapni nje faqe tjeter (p.sh. google.com) per te pare nese interneti funksionon. Nese ajo faqe ngarkohet, problemi mund te jete me platformen.', ARRAY['internet', 'lidhje', 'kontroll', 'rrjet', 'wifi'], 6),
('Teknike', 'Pse disa butona nuk funksionojne?', 'Provoni: 1) Rifreskoni faqen, 2) Caktivizoni bllokuesit e reklamave (ad blockers), 3) Provoni shfletues tjeter. Disa shtesa mund te interferojne.', ARRAY['buton', 'nuk', 'funksionon', 'kliko', 'problem'], 7),
('Teknike', 'A ka API per integrime?', 'Aktualisht nuk ofrojme API publik per integrime te jashtme. Per nevoja specifike, kontaktoni suportin teknik.', ARRAY['api', 'integrim', 'lidhje', 'automatizim', 'sistem'], 3),
('Teknike', 'Si te caktivizoj njoftimet e shfletuesit?', 'Ne cilesimet e shfletuesit, shkoni te Njoftimet dhe gjeni platformen. Mund te zgjidhni te pranoni ose bllokoni njoftimet.', ARRAY['caktivizo', 'njoftim', 'shfletues', 'blloko', 'ndalo'], 4),
('Teknike', 'Pse shoh version te vjeter te faqes?', 'Shfletuesi juaj mund te kete ruajtur version te vjeter ne cache. Pastroni cache-in (Ctrl+Shift+Delete) dhe rifreskoni faqen.', ARRAY['vjeter', 'version', 'cache', 'nuk', 'perditsohet'], 6),
('Teknike', 'A funksionon platforma ne iPad/Tablet?', 'Po, platforma funksionon ne te gjitha tabletat me shfletues modern. Faqja pershtatet automatikisht per madhesine e ekranit.', ARRAY['ipad', 'tablet', 'pajisje', 'ekran', 'suport'], 5),

-- SIGURIA (Security) - 15 entries
('Siguria', 'A jane te sigurta te dhenat e mia?', 'Po, platforma perdor enkriptim SSL/TLS per te gjitha komunikimet. Te dhenat ruhen ne servere te sigurte me backup te rregullte.', ARRAY['sigurt', 'te dhena', 'enkriptim', 'mbrojtje', 'privatesi'], 9),
('Siguria', 'Kush ka akses ne te dhenat e kompanise?', 'Vetem perdoruesit e autorizuar te kompanise suaj kane akses. Super admini ka akses per arsye menaxhimi te platformes.', ARRAY['akses', 'te dhena', 'kompani', 'kush', 'privatesi'], 8),
('Siguria', 'Si te mbroj llogarime?', 'Perdorni fjalekalim te forte (min. 6 karaktere, kombinim shkronjash, numrash, simbolesh). Mos e ndani fjalekalimin me askend. Dilni nga sistemi ne pajisje te perbashketa.', ARRAY['mbroj', 'llogari', 'siguri', 'fjalekalim', 'hack'], 9),
('Siguria', 'Cfare ndodh nese dikush hyn ne llogarime?', 'Ndryshoni fjalekalimin menjehere. Kontrolloni aktivitetin e fundit ne llogari. Njoftoni administratorin dhe suportin teknik.', ARRAY['hyn', 'llogari', 'hack', 'aksesi', 'paautorizuar'], 10),
('Siguria', 'A behet backup i te dhenave?', 'Po, te dhenat behen backup cdo dite automatikisht. Ne rast humbjeje, mund te rikuperohen brenda 30 diteve te fundit.', ARRAY['backup', 'rikuperim', 'humbje', 'ruajtje', 'kopje'], 7),
('Siguria', 'A ndahen te dhenat me pale te treta?', 'Jo, te dhenat tuaja nuk ndahen me pale te treta. Perdoren vetem per te ofruar sherbimet e platformes.', ARRAY['pale', 'treta', 'ndaj', 'te dhena', 'privatesi', 'gdpr'], 7),
('Siguria', 'Si funksionon enkriptimi?', 'Te gjitha te dhenat transmetohen permes HTTPS (SSL/TLS). Fjalekalimet ruhen si hash te enkriptuar. Skedaret ruhen ne menyre te sigurte.', ARRAY['enkriptim', 'ssl', 'https', 'siguri', 'hash'], 5),
('Siguria', 'A mund te fshij te gjitha te dhenat e mia?', 'Per fshirje te plote te te dhenave, kontaktoni suportin teknik. Ky proces eshte i pakthyeshem dhe kerkon verifikim shtese.', ARRAY['fshij', 'te dhena', 'gjithe', 'pakthyeshem', 'largo'], 6),
('Siguria', 'Si te raportoj nje cenim sigurie?', 'Kontaktoni menjehere suportin teknik permes chat-it te suportit. Pershkruani cfare ndodhi dhe kur. Mos beni ndryshime deri sa te merrni udhezime.', ARRAY['cenim', 'siguri', 'raportoj', 'incident', 'shkelje'], 10),
('Siguria', 'A ka autentikim me dy faktore?', 'Aktualisht autentikimi me dy faktore nuk eshte i disponueshem. Eshte ne zhvillim dhe do te shtohet se shpejti per siguri shtese.', ARRAY['dy', 'faktore', '2fa', 'mfa', 'autentikim', 'verifikim'], 6),
('Siguria', 'Cfare behet me llogari te paktivizuara?', 'Llogarite e paktivizuara nuk mund te aksesojne platformen, por te dhenat e tyre ruhen. Administratori mund ti riaktivizoje ne cdo kohe.', ARRAY['paktivizuar', 'llogari', 'joaktive', 'bllokuar'], 5),
('Siguria', 'Si te di nese dikush po provon te hyje ne llogarime?', 'Aktualisht nuk ka njoftim per perpjekje te deshtuar hyrjeje. Per mbrojtje, perdorni fjalekalim te forte dhe ndryshojeni rregullisht.', ARRAY['provon', 'hyje', 'perpjekje', 'alarmoj', 'sulm'], 6),
('Siguria', 'A eshte ne perputhje me GDPR?', 'Platforma respekton parimet e GDPR per mbrojtjen e te dhenave personale. Per informacion me te detajuar, shihni Politiken e Privatesise.', ARRAY['gdpr', 'privatesi', 'ligj', 'mbrojtje', 'rregullore'], 5),
('Siguria', 'Si te ndryshoj fjalekalimin rregullisht?', 'Rekomandojme ndryshimin e fjalekalimit cdo 3 muaj. Shkoni te Profili > Ndrysho Fjalekalimin dhe ndiqni hapat.', ARRAY['ndrysho', 'fjalekalim', 'rregullt', 'periodik', '3 muaj'], 5),
('Siguria', 'Cfare te bej nese marr email te dyshimte?', 'Mos klikoni asnje link ne email te dyshimte. Platforma nuk kerkon kurre fjalekalimin permes emailit. Raportoni emailin te suporti.', ARRAY['email', 'dyshimte', 'phishing', 'mashtrues', 'link'], 9),

-- PLATFORMA (Platform General) - 35 entries
('Platforma', 'Cfare eshte EuroPallet Logistics?', 'EuroPallet Logistics eshte nje platforme dixhitale per menaxhimin e paletave, depove, transportit, dhe komunikimit te stafit te kompanise suaj.', ARRAY['europallet', 'cfare', 'platforma', 'rreth', 'pershkrim'], 8),
('Platforma', 'Cilat jane karakteristikat kryesore?', 'Karakteristikat kryesore: menaxhim stoku, fletedergesa, chat i brendshem, dokumente, raporte, menaxhim deposh dhe shoferish.', ARRAY['karakteristika', 'vecore', 'funksion', 'ofron', 'kryesor'], 7),
('Platforma', 'Kush mund te perdore platformen?', 'Platforma perdoret nga kompani logjistike me role te ndryshme: administratore, punetore deposh, dhe shofere.', ARRAY['kush', 'perdor', 'perdorues', 'role', 'kompani'], 6),
('Platforma', 'A eshte e disponueshme 24/7?', 'Po, platforma eshte e disponueshme 24 ore ne dite, 7 dite ne jave. Mirembajtjet e planifikuara njoftohen paraprakisht.', ARRAY['disponueshem', '24', '7', 'gjithmone', 'kohe', 'orar'], 7),
('Platforma', 'Si te filloj me platformen?', 'Regjistrohuni me kompanine tuaj, zgjidhni planin, dhe filloni te shtoni depo dhe shofere. Chat-i i suportit eshte ketu per cdo pyetje.', ARRAY['fillo', 'filloj', 'nisje', 'start', 'perdor', 'hapa'], 8),
('Platforma', 'A ka udhezues perdorimi?', 'Po, chat-i i suportit ofron pergjigje per te gjitha pyetjet tuaja. Gjithashtu, udhezuesi i plote i perdorimit do te shtohet se shpejti.', ARRAY['udhezues', 'manual', 'tutorial', 'mesoj', 'ndihme', 'guidë'], 7),
('Platforma', 'Cfare ndodh kur perditsohet platforma?', 'Perditsime behen rregullisht pa nderpreje te sherbimit. Perditsimet e medha njoftohen paraprakisht me email.', ARRAY['perditesim', 'update', 'version', 'ri', 'ndryshim'], 5),
('Platforma', 'A mund te personalizoj platformen?', 'Mund te shtoni logon e kompanise, te krijoni kategori te personalizuara, dhe te organizoni depot sipas nevojave tuaja.', ARRAY['personalizo', 'ndryshoj', 'adapto', 'cilesime', 'konfigurim'], 5),
('Platforma', 'Si te marre ndihme me te shpejte?', 'Perdorni chat-in e suportit per pergjigje te menjehershme automatike. Per probleme komplekse, ekipi yne pergjigjet brenda disa oreve.', ARRAY['ndihme', 'shpejt', 'urgjent', 'suport', 'asistence'], 8),
('Platforma', 'A ka limit ne te dhenat qe mund te ruaj?', 'Hapesira e ruajtjes varet nga plani juaj. Plani Standard ofron hapesire te mjaftueshme per shumicen e kompanive.', ARRAY['limit', 'hapesire', 'ruajtje', 'storage', 'sasi', 'te dhena'], 5),
('Platforma', 'Ku ruhen te dhenat e mia?', 'Te dhenat ruhen ne servere te sigurte cloud me backup te rregullte. Serverat jane ne perputhje me standardet e sigurise europiane.', ARRAY['ku', 'ruhen', 'te dhena', 'server', 'cloud', 'vendndodhje'], 6),
('Platforma', 'A mund te integrohet me sisteme te tjera?', 'Aktualisht platforma funksionon si sistem i pavarur. Integrime me sisteme te tjera (ERP, kontabilitet) jane ne zhvillim.', ARRAY['integrim', 'sistem', 'tjeter', 'erp', 'kontabilitet', 'lidhje'], 4),
('Platforma', 'Si te jap feedback per platformen?', 'Perdorni chat-in e suportit per te derguar sugjerimet tuaja. Vleresojme cdo feedback per permiresimin e platformes.', ARRAY['feedback', 'sugjerim', 'mendim', 'vleresim', 'koment'], 5),
('Platforma', 'A ka statistika ne kohe reale?', 'Po, dashboardet shfaqin statistika te perditsuara ne kohe reale per stokun, dergesat, dhe aktivitetin e stafit.', ARRAY['statistika', 'reale', 'kohe', 'live', 'dashboard', 'perditsim'], 6),
('Platforma', 'Cfare rolit ka Super Admini?', 'Super Admini menaxhon te gjithe platformen: kompanite, planet, pagesat, dhe suportin teknik. Eshte roli me i larte ne sistem.', ARRAY['super', 'admin', 'rol', 'menaxhon', 'platforma'], 5),
('Platforma', 'Cfare rolit ka Admin Kompanise?', 'Admin Kompanise menaxhon gjithe veprimtarine e kompanise: depo, shofere, stok, fletedergesa, dokumente, raporte, dhe chat.', ARRAY['admin', 'kompani', 'rol', 'menaxhon', 'detyra'], 6),
('Platforma', 'Cfare bejne punetoret e depove?', 'Punetoret e depove menaxhojne pranimet, dergeset, stokun, dhe riparimet ne depon e tyre. Gjithashtu komunikojne permes chat-it.', ARRAY['punetor', 'depo', 'bejne', 'detyra', 'rol', 'pun'], 6),
('Platforma', 'Cfare bejne shoferet ne platforme?', 'Shoferet shohin fletedergesat e caktuara, ndryshojne statuset, ngarkojne foto te dorezimit, dhe komunikojne me stafin permes chat-it.', ARRAY['shofer', 'bejne', 'detyra', 'rol', 'pun', 'funksion'], 6),
('Platforma', 'A ka mundesi eksportimi te dhenash?', 'Funksioni i eksportimit ne CSV/Excel eshte ne zhvillim. Aktualisht mund te printoni faqet direkt nga shfletuesi.', ARRAY['eksporto', 'csv', 'excel', 'te dhena', 'shkarko', 'printo'], 5),
('Platforma', 'Si funksionon sistemi i njoftimeve?', 'Njoftimet dergoheni automatikisht per ngjarje te rendesishme: fletedergesa te reja, mesazhe, dokumente, ndryshime statusesh.', ARRAY['njoftim', 'sistem', 'automatik', 'alarm', 'ngjarje'], 6),
('Platforma', 'A mund te perdor platformen ne kompjuter dhe telefon?', 'Po, mund te aksesoni platformen nga cdo pajisje me shfletues interneti. Te dhenat sinkronizohen automatikisht mes pajisjeve.', ARRAY['kompjuter', 'telefon', 'pajisje', 'sinkronizo', 'akses'], 7),
('Platforma', 'Sa kohe merr per tu mesuar me platformen?', 'Platforma eshte projektuar te jete intuitive. Shumica e perdoruesve mesojne ta perdorin brenda 30 minutave me ndihmen e chat-it te suportit.', ARRAY['kohe', 'mesoj', 'perdor', 'lehte', 'filloj'], 6),
('Platforma', 'A ofrohet trajnim per stafin?', 'Chat-i i suportit ofron ndihme te menjehershme. Per trajnim te organizuar, kontaktoni ekipin tone per te planifikuar nje sesion.', ARRAY['trajnim', 'staf', 'mesim', 'udhezim', 'seance'], 5),
('Platforma', 'Cfare ndodh nese has gabim ne sistem?', 'Raportoni gabimin permes chat-it te suportit duke pershkruar cfare ndodhi, ne cilen faqe, dhe cfare po provonit te benit. Ekipi yne do te investigoje.', ARRAY['gabim', 'sistem', 'bug', 'problem', 'raportoj'], 8),
('Platforma', 'A ka plan per biznese te vogla?', 'Po, plani Free Trial (14 dite falas) dhe plani Standard jane te pershtatur per biznese te vogla dhe te mesme.', ARRAY['vogel', 'biznes', 'plan', 'cmim', 'pershtatur'], 6),
('Platforma', 'Si ta rekomandoj platformen te te tjeret?', 'Faleminderit per interesin! Ndani linkun e platformes me kolegete dhe partneret tuaj te biznesit. Cdo kompani regjistrohet ne menyre te pavarur.', ARRAY['rekomando', 'ndaj', 'tjeret', 'referim', 'ftoj'], 3),
('Platforma', 'A ka forum ose komunitet perdoruesish?', 'Aktualisht nuk ka forum te vecante. Chat-i i suportit eshte menyra me e mire per te marre ndihme dhe per te dhene sugjerime.', ARRAY['forum', 'komunitet', 'perdorues', 'diskutim'], 3),
('Platforma', 'Si me ndihmon platforma ne biznesin tim?', 'Platforma dixhitalizon proceset e logjistikes: gjurmim stoku ne kohe reale, fletedergesa dixhitale, komunikim i shpejte, dhe raporte te sakta.', ARRAY['ndihmon', 'biznes', 'perfitim', 'avantazh', 'vlere'], 7),
('Platforma', 'A mund te personalizoj njoftimet?', 'Aktualisht njoftimet dergoheni per te gjitha ngjarjet e rendesishme. Mundesia per te personalizuar njoftimet do te shtohet ne te ardhmen.', ARRAY['personalizo', 'njoftim', 'cilesime', 'zgjedh', 'konfigurim'], 4),
('Platforma', 'Cfare eshte Dashboard-i?', 'Dashboard-i eshte faqja kryesore qe shfaq nje permbledhje te shpejte: statistikat kryesore, njoftimet e fundit, dhe veprimet e shpeshta.', ARRAY['dashboard', 'cfare', 'kryefaqe', 'permbledhje', 'statistik'], 6),
('Platforma', 'Si te dal nga platforma ne menyre te sigurte?', 'Klikoni butonin "Dil" ne menus anesore ose ne header. Kjo mbyll sesionin tuaj ne menyre te sigurte.', ARRAY['dil', 'sigurte', 'shkyc', 'mbyll', 'sesion'], 7),
('Platforma', 'A mund te aksesoj platformen nga jashte vendit?', 'Po, platforma eshte e aksesueshme nga kudo ne bote ku keni lidhje interneti.', ARRAY['jashte', 'vend', 'akseso', 'nderkombetare', 'bote', 'huaj'], 5),
('Platforma', 'Cfare e ben kete platforme te ndryshme?', 'EuroPallet kombinon menaxhimin e stokut, transportit, komunikimit, dhe dokumenteve ne nje platforme te vetme te specializuar per paletat.', ARRAY['ndryshme', 'vecante', 'avantazh', 'krahaso', 'konkurent'], 5),
('Platforma', 'A ka support ne shqip?', 'Po, e gjithe platforma dhe suporti jane ne gjuhen shqipe. Suporti ne gjuhe te tjera do te shtohet ne te ardhmen.', ARRAY['shqip', 'gjuhe', 'suport', 'ndihme', 'komunikim'], 6),
('Platforma', 'Si te bej llogarine time me te sigurte?', 'Ndiqni keto keshilla: 1) Fjalekalim i forte, 2) Mos ndani kredencialet, 3) Dilni nga pajisjet publike, 4) Kontrolloni rregullisht aktivitetin.', ARRAY['sigurt', 'llogari', 'mbroj', 'keshilla', 'tips', 'praktika'], 7);
